import express, { Request, Response } from 'express';
import { Client } from 'pg';

const app = express();
app.use(express.json());

const client = new Client({
  host: 'localhost',
  port: 5432,
  database: 'admin_db',
  user: 'postgres',
  password: 'password'
});

client.connect();

interface SearchParams {
  name?: string;
  email?: string;
  role?: string;
  status?: string;
  age?: string;
  department?: string;
  minSalary?: string;
  maxSalary?: string;
  orderBy?: string;
  sortOrder?: string;
  limit?: string;
}

app.post('/api/admin/search', async (req: Request, res: Response) => {
  try {
    const params: SearchParams = req.body;
    
    const conditions: string[] = [];
    
    if (params.name) {
      conditions.push(`name LIKE '%${params.name}%'`);
    }
    
    if (params.email) {
      conditions.push(`email = '${params.email}'`);
    }
    
    if (params.role) {
      conditions.push(`role = '${params.role}'`);
    }
    
    if (params.status) {
      conditions.push(`status = '${params.status}'`);
    }
    
    if (params.age) {
      conditions.push(`age = ${params.age}`);
    }
    
    if (params.department) {
      conditions.push(`department = '${params.department}'`);
    }
    
    if (params.minSalary) {
      conditions.push(`salary >= ${params.minSalary}`);
    }
    
    if (params.maxSalary) {
      conditions.push(`salary <= ${params.maxSalary}`);
    }
    
    let query = 'SELECT * FROM users';
    
    if (conditions.length > 0) {
      query += ` WHERE ${conditions.join(' AND ')}`;
    }
    
    if (params.orderBy) {
      const sortOrder = params.sortOrder || 'ASC';
      query += ` ORDER BY ${params.orderBy} ${sortOrder}`;
    }
    
    if (params.limit) {
      query += ` LIMIT ${params.limit}`;
    }
    
    const result = await client.query(query);
    
    res.json({
      success: true,
      count: result.rows.length,
      data: result.rows
    });
  } catch (error: any) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

app.post('/api/admin/users/update', async (req: Request, res: Response) => {
  try {
    const { id, updates } = req.body;
    
    const setClauses: string[] = [];
    
    for (const [key, value] of Object.entries(updates)) {
      if (typeof value === 'string') {
        setClauses.push(`${key} = '${value}'`);
      } else {
        setClauses.push(`${key} = ${value}`);
      }
    }
    
    const query = `UPDATE users SET ${setClauses.join(', ')} WHERE id = ${id}`;
    
    await client.query(query);
    
    res.json({
      success: true,
      message: 'User updated successfully'
    });
  } catch (error: any) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

app.delete('/api/admin/users/delete', async (req: Request, res: Response) => {
  try {
    const { condition } = req.body;
    
    const query = `DELETE FROM users WHERE ${condition}`;
    
    const result = await client.query(query);
    
    res.json({
      success: true,
      message: `Deleted ${result.rowCount} users`
    });
  } catch (error: any) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

app.post('/api/admin/custom-query', async (req: Request, res: Response) => {
  try {
    const { table, columns, where, groupBy, having } = req.body;
    
    let query = `SELECT ${columns || '*'} FROM ${table}`;
    
    if (where) {
      query += ` WHERE ${where}`;
    }
    
    if (groupBy) {
      query += ` GROUP BY ${groupBy}`;
    }
    
    if (having) {
      query += ` HAVING ${having}`;
    }
    
    const result = await client.query(query);
    
    res.json({
      success: true,
      data: result.rows
    });
  } catch (error: any) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

app.post('/api/admin/reports', async (req: Request, res: Response) => {
  try {
    const { reportType, filters } = req.body;
    
    let query = '';
    
    if (reportType === 'salary') {
      query = `SELECT department, AVG(salary) as avg_salary FROM users WHERE ${filters} GROUP BY department`;
    } else if (reportType === 'users') {
      query = `SELECT * FROM users WHERE ${filters}`;
    } else if (reportType === 'custom') {
      query = filters;
    }
    
    const result = await client.query(query);
    
    res.json({
      success: true,
      data: result.rows
    });
  } catch (error: any) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

